import { useEffect, useState, useRef } from "react";
import { useNavigate } from "react-router-dom";

export const useLogoutHandler = () => {
  const navigate = useNavigate();
  const [showLogoutModal, setShowLogoutModal] = useState(false);
  const backClickCountRef = useRef(0);

  // Handle logout (only via logout button)
  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    setShowLogoutModal(false);
    backClickCountRef.current = 0; // Reset counter
    navigate("/login", { replace: true });
  };

  // Handle canceling logout (staying logged in) - resets back button counter
  const handleStayLoggedIn = () => {
    setShowLogoutModal(false);
    backClickCountRef.current = 0; // Reset counter when user chooses to stay
  };

  // Handle opening logout modal (from button click)
  const openLogoutModal = () => {
    setShowLogoutModal(true);
  };

  // Prevent back button navigation - never allow going back
  useEffect(() => {
    // Replace current state to prevent going back
    window.history.replaceState({ isDashboard: true }, "", window.location.pathname);

    // Listen for back button clicks
    const handlePopState = () => {
      backClickCountRef.current++;

      if (backClickCountRef.current === 1) {
        // First back click: show logout modal
        setShowLogoutModal(true);
      }
      
      // Always replace state to prevent actual navigation away from dashboard
      // This blocks all back button attempts
      window.history.replaceState({ isDashboard: true }, "", window.location.pathname);
    };

    window.addEventListener("popstate", handlePopState);

    return () => {
      window.removeEventListener("popstate", handlePopState);
    };
  }, []);

  return { 
    handleLogout, 
    handleStayLoggedIn,
    showLogoutModal, 
    setShowLogoutModal: openLogoutModal
  };
};
